#include<iostream>
#include<cstdio>
#include<algorithm>
using namespace std;

int main()
{
    int t;
    cin >> t;
    while(t--)
    {
        long long x, a, b;
        cin >> x >> a >> b;
        if(a == 1 && b != 0)
        {
            cout << x - x / b * b - b << endl; 
            continue;
        }
        while(x >= 0)
        {
            if(x * a - b >= x) break;
            x = a * x - b;
        }
        cout << x << endl;
    }
    return 0;
}
